--
-- Post-import FAL counter synchronization
--
UPDATE `tt_content` tc
SET tc.`image` = (
  SELECT COUNT(*) FROM `sys_file_reference` r
  WHERE r.uid_foreign = tc.uid
    AND r.tablenames = 'tt_content'
    AND r.fieldname = 'image'
    AND r.deleted = 0
    AND r.hidden = 0
);
UPDATE `tt_content` tc
SET tc.`media` = (
  SELECT COUNT(*) FROM `sys_file_reference` r
  WHERE r.uid_foreign = tc.uid
    AND r.tablenames = 'tt_content'
    AND r.fieldname = 'media'
    AND r.deleted = 0
    AND r.hidden = 0
);
UPDATE `tt_content` tc
SET tc.`file2` = (
  SELECT COUNT(*) FROM `sys_file_reference` r
  WHERE r.uid_foreign = tc.uid
    AND r.tablenames = 'tt_content'
    AND r.fieldname = 'file2'
    AND r.deleted = 0
    AND r.hidden = 0
);

--
-- Fallback image references for ns_theme_newage content elements
--
SELECT tc.pid, UNIX_TIMESTAMP(), UNIX_TIMESTAMP(), 0, 0, 0, 0, '', '', 0, 0, 0, 0, sf.uid, tc.uid, 'tt_content', 'image', 1, '', '', '', '', '{\"default\":{\"cropArea\":{\"x\":0,\"y\":0,\"width\":1,\"height\":1},\"selectedRatio\":\"NaN\",\"focusArea\":null}}', 0
FROM `tt_content` tc
JOIN `sys_file` sf ON sf.identifier LIKE '%/mobile.png'
LEFT JOIN `sys_file_reference` r ON r.tablenames='tt_content' AND r.uid_foreign=tc.uid AND r.fieldname='image' AND r.deleted=0
WHERE tc.CType IN ('nitsan_nsheader','ns_header') AND r.uid IS NULL;
