("1","1","1688730346","1688730346","0","0","0","0","256","","1","T3 New Age","1","3","ns_basetheme.website.settings.main_menu = 9INSERT INTO `tt_content` (`uid`, `pid`, `tstamp`, `crdate`, `deleted`, `hidden`, `starttime`, `endtime`, `fe_group`, `sorting`, `rowDescription`, `editlock`, `sys_language_uid`, `l18n_parent`, `l10n_source`, `l10n_state`, `l18n_diffsource`, `t3ver_oid`, `t3ver_wsid`, `t3ver_state`, `t3ver_stage`, `frame_class`, `colPos`, `table_caption`, `tx_impexp_origuid`, `CType`, `categories`, `layout`, `space_before_class`, `space_after_class`, `date`, `header`, `header_layout`, `header_position`, `header_link`, `subheader`, `bodytext`, `image`, `assets`, `imagewidth`, `imageheight`, `imageorient`, `imageborder`, `image_zoom`, `imagecols`, `pages`, `recursive`, `media`, `records`, `sectionIndex`, `linkToTop`, `pi_flexform`, `selected_categories`, `category_field`, `bullets_type`, `cols`, `table_class`, `table_delimiter`, `table_enclosure`, `table_header_position`, `table_tfoot`, `file_collections`, `filelink_size`, `filelink_sorting`, `filelink_sorting_direction`, `target`, `uploads_description`, `uploads_type`, `headline`, `subHeadline`, `btntxt`, `btnlink`, `text`, `file2`, `btn_text`, `link`, `contact_feature`, `beforeText`, `iconInText`, `afterText`, `contact`, `tx_themecamino_list_elements`, `tx_themecamino_link`, `tx_themecamino_link_label`, `tx_themecamino_link_icon`, `tx_themecamino_header_style`, `tx_themecamino_link_config`) VALUES 
("1","13","1688740844","1688730346","0","0","0","0","","256","","0","0","0","0","","{\"CType\":\"\",\"colPos\":\"\",\"pi_flexform\":\"\",\"space_before_class\":\"\",\"space_after_class\":\"\",\"sys_language_uid\":\"\",\"starttime\":\"\",\"endtime\":\"\",\"fe_group\":\"\",\"editlock\":\"\"}","0","0","0","0","default","0","","1","nitsan_nsourapp","0","0","","","0","","0","","","","","1","0",NULL,NULL,"0","0","0","2","","0","1","","1","0","<?xml version=\"1.0\" encoding=\"utf-8\" standalone=\"yes\" ?>\n<T3FlexForms>\n    <data>\n        <sheet index=\"sDEF\">\n            <language index=\"lDEF\">\n                <field index=\"text\">\n                    <value index=\"vDEF\">&lt;h2 class=&quot;section-heading&quot;&gt;Discover what all the buzz is about!&lt;/h2&gt;\n&lt;p&gt;Our app is available on any mobile device! Download now to get started!&lt;/p&gt;</value>\n                </field>\n                <field index=\"image1\">\n                    <value index=\"vDEF\">1</value>\n                </field>\n                <field index=\"link1\">\n                    <value index=\"vDEF\">#download</value>\n                </field>\n                <field index=\"image2\">\n                    <value index=\"vDEF\">1</value>\n                </field>\n                <field index=\"link2\">\n                    <value index=\"vDEF\">#download</value>\n                </field>\n                <field index=\"file2\">\n                    <value index=\"vDEF\">2</value>\n                </field>\n                <field index=\"file3\">\n                    <value index=\"vDEF\">1</value>\n                </field>\n            </language>\n        </sheet>\n    </data>\n</T3FlexForms>","0","","0","0","","124","0","0","0","","0","","","","0","0","","","","","<h2 class=\"section-heading\">Discover what all the buzz is about!</h2>\n<p>Our app is available on any mobile device! Download now to get started!</p>","2","","","0","","","","0","0","","","","0",""),
("2","12","1688730346","1688730346","0","0","0","0","","256","","0","0","0","0","","{\"pi_flexform\":\"\"}","0","0","0","0","default","0","","2","nitsan_nsfeature","0","0","medium","medium","0","Unlimited Features, Unlimited Fun","0","","","Check out what you can do with this app template!","","1","0",NULL,NULL,"0","0","0","2","","0","0","","1","0","<?xml version=\"1.0\" encoding=\"utf-8\" standalone=\"yes\" ?>\n<T3FlexForms>\n    <data>\n        <sheet index=\"sDEF\">\n            <language index=\"lDEF\">\n                <field index=\"headline\">\n                    <value index=\"vDEF\">Unlimited Features, Unlimited Fun</value>\n                </field>\n                <field index=\"subheadline\">\n                    <value index=\"vDEF\">Check out what you can do with this app template!</value>\n                </field>\n                <field index=\"image\">\n                    <value index=\"vDEF\">1</value>\n                </field>\n                <field index=\"iconInText\">\n                    <value index=\"vDEF\"></value>\n                </field>\n                <field index=\"contact\">\n                    <el index=\"el\">\n                        <field index=\"61b9bf5393756279278005\">\n                            <value index=\"container\">\n                                <el>\n                                    <field index=\"title\">\n                                        <value index=\"vDEF\">Device Mockups</value>\n                                    </field>\n                                    <field index=\"text\">\n                                        <value index=\"vDEF\">Put an image, video, animation, or anything else in the screen!</value>\n                                    </field>\n                                    <field index=\"socialIcon\">\n                                        <value index=\"vDEF\">icon-screen-smartphone</value>\n                                    </field>\n                              